import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { RealtimeClient } from './client';
import { SocketChannel } from './types';
import { io } from 'socket.io-client';

// Mock socket.io-client
vi.mock('socket.io-client', () => {
  const mockSocket = {
    on: vi.fn(),
    off: vi.fn(),
    emit: vi.fn(),
    disconnect: vi.fn(),
    removeAllListeners: vi.fn(),
    connected: false,
  };
  return {
    io: vi.fn(() => mockSocket),
  };
});

const mockedIo = vi.mocked(io);

describe('RealtimeClient', () => {
  let client: RealtimeClient;
  const defaultConfig = {
    url: 'http://localhost:3000',
    getToken: () => 'test-jwt-token',
    apiBaseUrl: 'http://localhost:3000/api',
  };

  beforeEach(() => {
    vi.useFakeTimers();
    client = new RealtimeClient(defaultConfig);
  });

  afterEach(() => {
    client.disconnect();
    vi.useRealTimers();
    vi.restoreAllMocks();
  });

  describe('initial state', () => {
    it('starts in disconnected state', () => {
      expect(client.getConnectionState()).toBe('disconnected');
    });

    it('is not in degraded mode initially', () => {
      expect(client.isDegraded()).toBe(false);
    });
  });

  describe('connect', () => {
    it('transitions to connecting state when token is available', () => {
      const stateChanges: string[] = [];
      client.on('connection-state-change', (state) => {
        stateChanges.push(state as string);
      });

      client.connect();

      expect(stateChanges).toContain('connecting');
    });

    it('stays disconnected when no token is available', () => {
      const noTokenClient = new RealtimeClient({
        ...defaultConfig,
        getToken: () => null,
      });

      noTokenClient.connect();
      expect(noTokenClient.getConnectionState()).toBe('disconnected');
      noTokenClient.disconnect();
    });
  });

  describe('disconnect', () => {
    it('transitions to disconnected state', () => {
      client.connect();
      client.disconnect();
      expect(client.getConnectionState()).toBe('disconnected');
    });
  });

  describe('subscription management', () => {
    it('tracks subscribed channels', () => {
      client.subscribe(SocketChannel.SERVER_STATUS);
      client.subscribe(SocketChannel.MARKETPLACE_UPDATES);
      // No error thrown, channels are tracked internally
      client.unsubscribe(SocketChannel.SERVER_STATUS);
    });
  });

  describe('event listeners', () => {
    it('registers and triggers event callbacks', () => {
      const callback = vi.fn();
      client.on('test-event', callback);

      // Simulate emitting through the internal mechanism
      // In real usage, the socket would trigger this
      // For unit testing, we verify the listener registration works
      expect(callback).not.toHaveBeenCalled();
    });

    it('removes event callbacks', () => {
      const callback = vi.fn();
      client.on('test-event', callback);
      client.off('test-event', callback);
      // Callback should be removed
    });
  });

  describe('degraded mode', () => {
    it('reports isDegraded correctly based on connection state', () => {
      // Initially not degraded
      expect(client.isDegraded()).toBe(false);
    });
  });

  describe('configuration defaults', () => {
    it('uses 5000ms connection timeout by default', () => {
      client.connect();
      expect(mockedIo).toHaveBeenCalledWith(
        defaultConfig.url,
        expect.objectContaining({
          timeout: 5000,
        }),
      );
    });

    it('uses JWT token in auth', () => {
      client.connect();
      expect(mockedIo).toHaveBeenCalledWith(
        defaultConfig.url,
        expect.objectContaining({
          auth: { token: 'test-jwt-token' },
        }),
      );
    });

    it('disables built-in reconnection (handled manually)', () => {
      client.connect();
      expect(mockedIo).toHaveBeenCalledWith(
        defaultConfig.url,
        expect.objectContaining({
          reconnection: false,
        }),
      );
    });

    it('uses websocket transport', () => {
      client.connect();
      expect(mockedIo).toHaveBeenCalledWith(
        defaultConfig.url,
        expect.objectContaining({
          transports: ['websocket'],
        }),
      );
    });
  });
});

